#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n;
        scanf("%d", &n);
        unsigned long long fact = 1ULL;
        for (int i = 2; i <= n; ++i) {
            fact *= i;
        }
        printf("The factorial of the given number is: %llu", fact);
        if (T) printf("\n");
    }
    return 0;
}

